final:
module top_module(
  input in,
  input Vthp,
  input Vthn,
  output out
);reg prev_out;
  wire _tap_in = in & {1{1'b1}};


  always @(in or Vthp or Vthn or prev_out) begin
    if (in > Vthp) begin
      prev_out <= 1;
    end else if (in < Vthn) begin
      prev_out <= 0;
    end
  end

  assign out = prev_out;

endmodule
